function getWholeDebt(
    address _market,
    address _tokenAddr,
    uint256 _borrowType,
    address _debtOwner
) internal view returns (uint256 wholeDebt) {
    uint256 STABLE_ID = 1;
    uint256 VARIABLE_ID = 2;

    IAaveProtocolDataProviderV2 dataProvider = getDataProvider(_market);
    (, uint256 borrowsStable, uint256 borrowsVariable,,,,,,) =
        dataProvider.getUserReserveData(_tokenAddr, _debtOwner);

    if (_borrowType == STABLE_ID) {
        wholeDebt = borrowsStable;
    } else if (_borrowType == VARIABLE_ID) {
        wholeDebt = borrowsVariable;
    }
}

function parseSubData(bytes calldata _encodedInput)
        public
        pure
        returns (CompV3SubData memory sub)
    {
        sub.market = address(bytes20(_encodedInput[0:20]));
        sub.baseToken = address(bytes20(_encodedInput[20:40]));
        sub.minRatio = uint128(bytes16(_encodedInput[40:56]));
        sub.maxRatio = uint128(bytes16(_encodedInput[56:72]));
        sub.targetRatioBoost = uint128(bytes16(_encodedInput[72:88]));
        sub.targetRatioRepay = uint128(bytes16(_encodedInput[88:104]));
        sub.boostEnabled = (bytes1(_encodedInput[104:105])) != bytes1(0x00); // compare to get bool
        sub.isEOA = (bytes1(_encodedInput[105:106])) != bytes1(0x00); // compare to get bool
    }

function _removeTriggers(Params memory params) internal {
    for (uint256 i = 0; i < params.cdpIds.length; ++i) {
        bytes memory callData = abi.encodeWithSelector(
            IAutomationBot.removeTrigger.selector, params.cdpIds[i], params.triggerIds[i], true
        );

        (bool success, bytes memory returnData) =
            address(SF_AUTOMATION_BOT).delegatecall(callData);

        if (!success) {
            if (returnData.length > 0) {
                assembly {
                    let returndata_size := mload(returnData)
                    revert(add(32, returnData), returndata_size)
                }
            } else {
                revert SummerfiUnsub_DelegatecallFailed();
            }
        }
    }
}

