function getOperationHash(
    IBridge bridge_,
    string calldata network_,
    bytes calldata redeemDetails_
) external view virtual returns (bytes32) {
    ERC20RedeemData memory redeem_ = abi.decode(redeemDetails_, (ERC20RedeemData));

    return
        keccak256(
            abi.encodePacked(
                redeem_.token,
                redeem_.amount,
                redeem_.receiver,
                redeem_.batch,
                redeem_.operationType,
                redeem_.nonce,
                network_,
                address(bridge_)
            )
        );
}

function _upgradeContractAndCall(
    string memory name_,
    address newImplementation_,
    bytes memory data_
) internal virtual {
    AContractsRegistryStorage storage $ = _getAContractsRegistryStorage();

    address contractToUpgrade_ = $.contracts[name_];

    if (contractToUpgrade_ == address(0)) revert NoMappingExists(name_);
    if (!$.isProxy[contractToUpgrade_]) revert NotAProxy(name_, contractToUpgrade_);

    $.proxyUpgrader.upgrade(contractToUpgrade_, newImplementation_, data_);

    emit ProxyContractUpgraded(name_, newImplementation_);
}

function readEIP1559ScriptArtifact(string memory path)
        internal
        view
        virtual
        returns (EIP1559ScriptArtifact memory)
    {
        string memory data = vm.readFile(path);
        bytes memory parsedData = vm.parseJson(data);
        RawEIP1559ScriptArtifact memory rawArtifact = abi.decode(parsedData, (RawEIP1559ScriptArtifact));
        EIP1559ScriptArtifact memory artifact;
        artifact.libraries = rawArtifact.libraries;
        artifact.path = rawArtifact.path;
        artifact.timestamp = rawArtifact.timestamp;
        artifact.pending = rawArtifact.pending;
        artifact.txReturns = rawArtifact.txReturns;
        artifact.receipts = rawToConvertedReceipts(rawArtifact.receipts);
        artifact.transactions = rawToConvertedEIPTx1559s(rawArtifact.transactions);
        return artifact;
    }

function rawToConvertedEIP1559Detail(RawTx1559Detail memory rawDetail)
        internal
        pure
        virtual
        returns (Tx1559Detail memory)
    {
        Tx1559Detail memory txDetail;
        txDetail.data = rawDetail.data;
        txDetail.from = rawDetail.from;
        txDetail.to = rawDetail.to;
        txDetail.nonce = _bytesToUint(rawDetail.nonce);
        txDetail.txType = _bytesToUint(rawDetail.txType);
        txDetail.value = _bytesToUint(rawDetail.value);
        txDetail.gas = _bytesToUint(rawDetail.gas);
        txDetail.accessList = rawDetail.accessList;
        return txDetail;
    }

function deal(address token, address to, uint256 give, bool adjust) internal virtual {
    // get current balance
    (, bytes memory balData) = token.staticcall(abi.encodeWithSelector(0x70a08231, to));
    uint256 prevBal = abi.decode(balData, (uint256));

    // update balance
    _stdstore.target(token).sig(0x70a08231).with_key(to).checked_write(give);

    // update total supply
    if (adjust) {
        (, bytes memory totSupData) = token.staticcall(abi.encodeWithSelector(0x18160ddd));
        uint256 totSup = abi.decode(totSupData, (uint256));
        if (give < prevBal) {
            totSup -= (prevBal - give);
        } else {
            totSup += (give - prevBal);
        }
        _stdstore.target(token).sig(0x18160ddd).checked_write(totSup);
    }
}

function set(uint256 chainId, string memory key, bool[] memory value) public {
    Type memory ty = Type(TypeKind.Bool, true);
    _ensureTypeConsistency(chainId, key, ty);
    _dataOf[chainId][key] = abi.encode(value);
    if (_writeToFile) {
        string memory json = "[";
        for (uint256 i = 0; i < value.length; i++) {
            json = string.concat(json, vm.toString(value[i]));
            if (i < value.length - 1) json = string.concat(json, ",");
        }
        json = string.concat(json, "]");
        _writeToToml(chainId, ty.kind.toTomlKey(), key, json);
    }
}

