function dollarBalances() public view returns (uint256 frax_val_e18, uint256 collat_val_e18) {
    // Get the allocations
    uint256[10] memory allocations = showAllocations();

    // FRAX portion is Frax * CR
    uint256 frax_portion_with_cr = (allocations[2] * FRAX.global_collateral_ratio()) / PRICE_PRECISION;

    // Collateral portion
    uint256 collat_portion = allocations[8];

    // Total value, not including CR, ignoring FXS
    frax_val_e18 = allocations[2] + allocations[8];

    // Collat value, accounting for CR on the FRAX portion
    collat_val_e18 = collat_portion + frax_portion_with_cr;
}

function extractAccountFromProof(
    bytes32 _addressHash, // keccak256(abi.encodePacked(address))
    bytes32 _stateRootHash,
    RLPReader.RLPItem[] memory _proof
)
    internal pure returns (Account memory)
{
    bytes memory acctRlpBytes = MerklePatriciaProofVerifier.extractProofValue(
        _stateRootHash,
        abi.encodePacked(_addressHash),
        _proof
    );

    Account memory account;

    if (acctRlpBytes.length == 0) {
        return account;
    }

    RLPReader.RLPItem[] memory acctFields = acctRlpBytes.toRlpItem().toList();
    require(acctFields.length == 4);

    account.exists = true;
    account.nonce = acctFields[0].toUint();
    account.balance = acctFields[1].toUint();
    account.storageRoot = bytes32(acctFields[2].toUint());
    account.codeHash = bytes32(acctFields[3].toUint());

    return account;
}

function _addSigners(address account, bytes[] memory newSigners) internal virtual override {
    uint256 newSignersLength = newSigners.length;
    for (uint256 i = 0; i < newSignersLength; i++) {
        (uint256 deadline, bytes memory signer, bytes memory signature) = abi.decode(
            newSigners[i],
            (uint256, bytes, bytes)
        );
        require(deadline > block.timestamp, ERC7579MultisigExpiredConfirmation(deadline));
        require(
            SignatureChecker.isValidSignatureNow(signer, _signableConfirmationHash(account, deadline), signature),
            ERC7579MultisigInvalidConfirmationSignature(signer)
        );
        newSigners[i] = signer; // Replace the ABI-encoded value with the signer
    }
    super._addSigners(account, newSigners);
}

function _prefund(
    PackedUserOperation calldata userOp,
    bytes32 userOpHash,
    IERC20 token,
    uint256 tokenPrice,
    address prefunder_,
    uint256 maxCost
)
    internal
    virtual
    override
    returns (bool prefunded, uint256 prefundAmount, address prefunder, bytes memory prefundContext)
{
    address guarantor = _fetchGuarantor(userOp);
    bool isGuaranteed = guarantor != address(0);
    (prefunded, prefundAmount, prefunder, prefundContext) = super._prefund(
        userOp,
        userOpHash,
        token,
        tokenPrice,
        isGuaranteed ? guarantor : prefunder_,
        maxCost + (isGuaranteed ? 0 : _guaranteedPostOpCost())
    );
    if (prefunder == guarantor) {
        emit UserOperationGuaranteed(userOpHash, prefunder, prefundAmount);
    }
    return (prefunded, prefundAmount, prefunder, abi.encodePacked(prefundContext, userOp.sender));
}

function _requestRedeem(
    uint256 shares,
    address controller,
    address owner,
    uint256 requestId
) internal virtual returns (uint256) {
    require(_isRedeemAsync(), ERC7540SyncRedeem());

    address sender = _msgSender();
    if (owner != sender && !isOperator(owner, sender)) {
        _spendAllowance(owner, sender, shares);
    }
    if (_redeemShareDestination() == address(0)) {
        _totalPendingRedeemShares += shares;
        _burn(owner, shares);
    } else {
        _transfer(owner, _redeemShareDestination(), shares);
    }

    emit RedeemRequest(controller, owner, requestId, _msgSender(), shares);
    return requestId;
}

function _fulfillDeposit(uint256 assets, uint256 shares, address controller) internal virtual {
    uint256 pendingAssets = pendingDepositRequest(0, controller);
    require(assets <= pendingAssets, ERC7540DepositInsufficientPendingAssets(assets, pendingAssets));

    _deposits[controller].pendingAssets -= assets;
    _deposits[controller].claimableAssets += assets;
    _deposits[controller].claimableShares += shares;

    if (_depositShareOrigin() != address(0)) {
        _mintSharesOnDepositFulfill(assets, shares);
    }

    emit DepositClaimable(controller, 0, assets, shares);
}
